var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내 몸에 흐르는 피를 용혈이라고 부른대.","JPN":"私の体に流れる血を、龍血と呼ぶらしいわ。","ENG":"They call the blood in my veins Dragon Blood.","TWN":"他們說我身體裡流著的血叫做龍血。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"멋지지 않아? 용!","JPN":"龍だなんて、かっこいいと思わない？","ENG":"Cool, right? Dragon!","TWN":"很帥氣吧？龍！"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"사람을 해할 뿐인 짐승들일세.","JPN":"所詮は人を害するケモノにすぎん。","ENG":"They're just Beasts that bring harm to people.","TWN":"那只是會傷害人的野獸而已。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그런 짐승의 피를 타고나는 것을… 빈말이라도 어찌 멋지다 할 수 있겠나.","JPN":"そのようなケモノの血を持って生まれることを……お世辞にも格好いいとは言えんな。","ENG":"How could I ever call it… admirable, even as a joke, that I was born with Beast Blood?","TWN":"繼承那樣的野獸之血…就算玩笑話，也無法說是帥氣。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 너무 나쁜 쪽으로만 생각해서 탈이라니까.","JPN":"あなたは思考回路がネガティブすぎるの。","ENG":"You always look at things from the worst possible angle. That's your problem.","TWN":"你就是太愛往壞處想了。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장 말처럼- <color=#ffd34c>땅내림</color>이란 건 받아들이기 나름인 거야.","JPN":"アカタツ隊長の言葉通り、<color=#ffd34c>チガカリ</color>は受け入れ方次第なのよ。","ENG":"Like Commander Myeongdal says, \\"Being <color=#ffd34c>Earthbound</color> is all about how you accept it.\\"","TWN":"就像明達隊長說的—地脈之力取決於你如何去接受。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이 용혈 덕분에, 총알 날아다니는 시대에 칼 한 자루로 사람들을 도울 수 있는 거라고.","JPN":"龍血のおかげで、弾丸が飛び交うこの時代に剣一本で人を助けられるのだから。","ENG":"Thanks to this Dragon Blood, I can still help people with nothing but a sword, even in a world full of guns and bullets.","TWN":"多虧這龍血，在這個槍彈橫行的時代，我才能只靠一把刀來幫助人們。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"내 피 덕분에, 전생의 우리가 용을 잡을 수도 있었고 말이지.","JPN":"某の血のおかげで、前世の我らは龍を倒せたしな。","ENG":"And thanks to my blood, our past selves were able to slay dragons.","TWN":"多虧了我的血，我們前世才能抓住龍。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"전생에 날 구해준 은인이라고 또 잘난 척하는 거야? 정작 자긴 기억도 못하면서.","JPN":"前世で私を助けた恩人だからって、また偉ぶるつもり？　どうせ覚えてもいないくせに。","ENG":"Oh, here we go. Bragging about being my savior in a past life again? Not like you even remember it.","TWN":"又在炫耀是前世救了你的恩人嗎？結果你自己卻不記得。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"누가 알겠나? 이번 생에도 내가 또 한 번 그대 목숨을 구하게 될지.","JPN":"今生で某がもう一度、そなたの命を助けることだってあるかもしれん。","ENG":"Who knows? I might just end up saving your life all over again in this one.","TWN":"誰知道呢？或許在這一世，我會再救你一次。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가 겪어본 적도 없는 시절을 떠올린다는 건 되게 기묘하네.","JPN":"自分が経験したこともない過去を思い出すって、妙な気分ね。","ENG":"It's strange, isn't it? Remembering a time I never lived through.","TWN":"回想我從未經歷過的時代，感覺很奇妙。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신이랑 내가 죽고 못사는 사이였다는 것도 믿기지 않아. 딱히 끌리는 매력도 없고, 맨날 공부만 빠져 사는 사내인데.","JPN":"あなたと私が深く愛し合う関係だったってことも信じられないわ。これといって心惹かれるような魅力もないし、勉強しか頭にない男なのに。","ENG":"Hard to believe you and I were once hopelessly in love. You're not even my type. I'm all books and brooding.","TWN":"我無法相信你和我曾經是那種關係。你也沒有特別吸引人的魅力，每天只知道學習。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그대가 날 마음에 안 들어 하면, 이번 생에는 적당한 동료 사이로 지내다 끝날지도 모르지.","JPN":"そなたが某のことを気に入らぬなら、今生は単なる同僚の仲で終わるかもしれんな。","ENG":"If I don't appeal to you, then maybe in this life we're just meant to stay comrades.","TWN":"如果你不喜歡我，那這一世我們或許就以適當的夥伴關係結束吧。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"마음에 안 든다고 한 적은 없거든?","JPN":"気に入らないとは言ってない。","ENG":"Hey, I never said I didn't like you.","TWN":"我可沒說不喜歡你？"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그리고 운명이 장난인가? 우리가 내키든 내키지 않든, 무조건 그렇게 될 수밖에 없는 게 운명이라고.","JPN":"あと、運命はそんな軽いものじゃないわ。私たちの意志と関係なく、そうなるしかないのが運命というものよ。","ENG":"And don't make light of fate. Whether we like it or not, it pulls us along all the same.","TWN":"還有，命運是開玩笑的嗎？無論我們是否情願，都會變成那樣的，這就是命運。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니까, 내 비위에 맞춰주는 시늉이라도 좀 하는 게 어때?","JPN":"だから、私の機嫌を取るふりでもしたらどう？","ENG":"So how about you try a little harder to be charming, hmm?","TWN":"所以，你是不是該假裝順著我的心意一點？"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"운명이 정해 놓았다면 구태여 비위를 맞출 필요도 없겠지.","JPN":"運命によって決められているなら、わざわざ機嫌を取る必要もなかろう。","ENG":"If fate's already decided everything, I don't need to try anything at all.","TWN":"既然命運已經注定，那就不需要特地去迎合。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"어련히 그대가 날 좋아할 수밖에 없는 게 운명이란 것 아닌가.","JPN":"そなたが某を好いてしまうのが運命というものであるゆえ。","ENG":"Fate means you're going to fall for me whether you want to or not.","TWN":"難道不是你注定會喜歡上我嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"와아, 말도 안 돼. 이런 왕재수하고 살 바엔 운명을 거스르고 말겠다.","JPN":"はあ、あり得ない。こんないけ好かない男と生涯を添い遂げるぐらいなら、運命に逆らってやるわ。","ENG":"Ugh, gross. I'd rather defy fate than end up with someone so full of himself.","TWN":"哇，太過分了。與其和這種討厭的傢伙一起生活，我寧願違抗命運。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그렇게 하겠다면 이쪽도 별 이의는 없네.","JPN":"そうしたいならこちらとしても異見はない。","ENG":"Well, if that's your choice, I won't object.","TWN":"如果你這麼想，我也沒有異議。"},"stage":{"bg":"HANOK_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmph.","TWN":"哼。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmph.","TWN":"哼。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"만난 지 얼마나 됐다고, 벌써 지지고 볶는 사이가 된 거냐?","JPN":"出会って日も浅いというのに、もうそんなに仲良くなったのか。","ENG":"How long's it been, and you two already bicker like an old couple?","TWN":"才剛見面沒多久，就變成打打鬧鬧的關係了嗎？"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"보아하니, 조만간 같은 방까지 내어 달라고 하겠구나.","JPN":"近いうちに部屋も一緒にしてくれと言い出しそうだな。","ENG":"At this rate, you'll be asking for a shared room before long.","TWN":"看來，你們很快就要要求住進同一個房間了。"},"stage":{"bg":"HANOK_02","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};